import { db } from "@/utils/db";
import { sessionChart } from "@/utils/schema";
import { eq } from "drizzle-orm";
import { NextResponse } from "next/server";
import { GoogleGenerativeAI } from "@google/generative-ai";

const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY!);

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { sessionId, sessionDetail, messages } = body;

    if (!sessionId || !sessionDetail || !messages) {
      return NextResponse.json({ error: "Missing required fields" }, { status: 400 });
    }

    const { selectedDoctor, notes } = sessionDetail;

    const prompt = `
      You are an expert medical scribe. Analyze the following conversation between a user and an AI Medical Agent (${selectedDoctor.specialist}).
      User's initial chief complaint notes: "${notes}"

      Conversation Transcripts:
      ${JSON.stringify(messages, null, 2)}

      Generate a structured medical report based on this conversation.
      You MUST return ONLY a valid JSON object with the following structure, with NO Markdown wrappers like \`\`\`json:
      {
        "agentName": "${selectedDoctor.specialist}",
        "chiefComplaint": "string (summarize the main issue)",
        "summary": "string (1-2 paragraph summary of the consultation)",
        "symptoms": [{"symptom": "name of symptom", "duration": "string", "severity": "string"}],
        "medicationMentioned": [{"name": "string", "dosage": "string", "frequency": "string"}],
        "recommendations": ["string (actionable next steps)"],
        "disclaimer": "This report was generated by AI. Please consult a real doctor for medical advice."
      }
    `;

    const model = genAI.getGenerativeModel({ model: "gemini-2.5-flash", generationConfig: { responseMimeType: "application/json" } });
    const result = await model.generateContent(prompt);
    let reportJsonText = result.response.text();

    const reportObj = JSON.parse(reportJsonText);

    // Update DB
    await db
      .update(sessionChart)
      .set({
        conversation: messages,
        report: reportObj,
      })
      .where(eq(sessionChart.sessionId, sessionId));

    return NextResponse.json({ success: true, report: reportObj });
  } catch (error) {
    console.error("Error POST /api/medical-report:", error);
    return NextResponse.json({ error: "Internal Server Error" }, { status: 500 });
  }
}

"use client";

import { useUserDetail } from "@/app/provider";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Textarea } from "@/components/ui/textarea";
import { doctorAgents, DoctorAgent } from "@/data/doctorAgents";
import axios from "axios";
import { Loader2 } from "lucide-react";
import { useRouter } from "next/navigation";
import { useState } from "react";
import { toast } from "sonner";
import { v4 as uuidv4 } from "uuid";

interface AddNewSessionDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  isPaidUser: boolean;
  hasHistory: boolean;
}

export function AddNewSessionDialog({
  isOpen,
  onOpenChange,
  isPaidUser,
  hasHistory,
}: AddNewSessionDialogProps) {
  const { userDetail } = useUserDetail();
  const router = useRouter();
  const [step, setStep] = useState(1);
  const [symptoms, setSymptoms] = useState("");
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [suggestedDoctors, setSuggestedDoctors] = useState<DoctorAgent[]>([]);
  const [selectedDoctor, setSelectedDoctor] = useState<DoctorAgent | null>(null);

  // If free user and already has history, they can't start a new session
  const isLocked = !isPaidUser && hasHistory;

  const analyzeSymptoms = async () => {
    if (!symptoms.trim()) return;
    setIsAnalyzing(true);

    try {
      // In a real app we'd call Gemini here to suggest specialists based on symptoms.
      // For now, we'll just suggest General Physician and Pediatrician as defaults 
      // or filter based on simple keyword matching.

      const keywords = symptoms.toLowerCase();
      let matches = doctorAgents.filter(d => 
        keywords.includes(d.specialist.toLowerCase()) ||
        keywords.includes("heart") && d.specialist === "Cardiologist" ||
        keywords.includes("skin") && d.specialist === "Dermatologist" ||
        keywords.includes("child") && d.specialist === "Pediatrician" ||
        keywords.includes("bone") && d.specialist === "Orthopedic"
      );

      if (matches.length === 0) {
        matches = [doctorAgents[0]]; // Default to General Physician
      }

      setSuggestedDoctors(matches);
      setStep(2);
    } catch (error) {
      console.error(error);
      toast.error("Failed to analyze symptoms");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const createSession = async () => {
    if (!selectedDoctor) return;
    setIsAnalyzing(true);

    try {
      const sessionId = uuidv4();
      await axios.post("/api/session-chart", {
        sessionId,
        notes: symptoms,
        selectedDoctor,
      });

      onOpenChange(false);
      router.push(`/dashboard/medical-agent/${sessionId}`);
    } catch (error) {
      console.error(error);
      toast.error("Failed to create session");
      setIsAnalyzing(false);
    }
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Start a New Consultation</DialogTitle>
          <DialogDescription>
            {isLocked
              ? "You have reached your free consultation limit. Upgrade to Pro for unlimited sessions."
              : "Describe your symptoms or what's bothering you, and we'll suggest the best specialist."}
          </DialogDescription>
        </DialogHeader>

        {isLocked ? (
          <div className="flex flex-col items-center justify-center py-8">
            <Button onClick={() => router.push("/dashboard/billing")}>
              Upgrade to Pro
            </Button>
          </div>
        ) : step === 1 ? (
          <div className="space-y-4 py-4">
            <Textarea
              placeholder="e.g., I've been having a persistent headache for the past 3 days along with some nausea..."
              className="min-h-[200px]"
              value={symptoms}
              onChange={(e) => setSymptoms(e.target.value)}
            />
            <div className="flex justify-end">
              <Button
                onClick={analyzeSymptoms}
                disabled={!symptoms.trim() || isAnalyzing}
              >
                {isAnalyzing && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Next: Find Specialist
              </Button>
            </div>
          </div>
        ) : (
          <div className="space-y-4 py-4">
            <h4 className="font-medium">Suggested Specialists</h4>
            <div className="grid gap-4 md:grid-cols-2">
              {suggestedDoctors.map((doc) => (
                <div
                  key={doc.id}
                  className={`cursor-pointer rounded-lg border p-4 transition-all ${
                    selectedDoctor?.id === doc.id
                      ? "border-primary bg-primary/5 ring-1 ring-primary"
                      : "hover:border-primary/50"
                  }`}
                  onClick={() => setSelectedDoctor(doc)}
                >
                  <h5 className="font-semibold">{doc.specialist}</h5>
                  <p className="mt-1 text-xs text-muted-foreground line-clamp-2">
                    {doc.description}
                  </p>
                </div>
              ))}
            </div>

            <div className="flex justify-between pt-4">
              <Button variant="outline" onClick={() => setStep(1)}>
                Back
              </Button>
              <Button
                onClick={createSession}
                disabled={!selectedDoctor || isAnalyzing}
              >
                {isAnalyzing && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                Start Voice Call
              </Button>
            </div>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { DoctorAgent } from "@/data/doctorAgents";
import { useUserDetail } from "@/app/provider";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import Image from "next/image";

interface DoctorAgentCardProps {
  doctor: DoctorAgent;
  onSelect: (doctor: DoctorAgent) => void;
  isPaidUser: boolean;
}

export function DoctorAgentCard({ doctor, onSelect, isPaidUser }: DoctorAgentCardProps) {
  const isLocked = doctor.subscriptionRequired && !isPaidUser;

  return (
    <div className="relative flex flex-col rounded-xl border bg-card p-4 shadow-sm transition-all hover:shadow-md">
      {doctor.subscriptionRequired && (
        <Badge className="absolute right-4 top-4 z-10" variant="secondary">
          Premium
        </Badge>
      )}

      <div className="mb-4 aspect-square relative overflow-hidden rounded-lg bg-muted">
        {/* Placeholder image if not found */}
        <div className="absolute inset-0 flex items-center justify-center text-4xl bg-primary/10 text-primary uppercase font-bold">
          {doctor.specialist.charAt(0)}
        </div>
      </div>

      <div className="flex-1">
        <h3 className="font-semibold text-lg">{doctor.specialist}</h3>
        <p className="mt-2 line-clamp-2 text-sm text-muted-foreground">
          {doctor.description}
        </p>
      </div>

      <Button
        className="mt-4 w-full"
        variant={isLocked ? "secondary" : "default"}
        disabled={isLocked}
        onClick={() => onSelect(doctor)}
      >
        {isLocked ? "Upgrade to Access" : "Start Consultation"}
      </Button>
    </div>
  );
}

import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import moment from "moment";
import { useState } from "react";

interface Report {
  agentName: string;
  chiefComplaint: string;
  summary: string;
  symptoms: { symptom: string; duration: string; severity: string }[];
  medicationMentioned: { name: string; dosage: string; frequency: string }[];
  recommendations: string[];
  disclaimer: string;
}

interface Session {
  id: number;
  sessionId: string;
  notes: string;
  selectedDoctor: any;
  report: Report | null;
  createdOn: string;
}

interface HistoryTableProps {
  sessions: Session[];
}

export function HistoryTable({ sessions }: HistoryTableProps) {
  const [selectedReport, setSelectedReport] = useState<Report | null>(null);
  const [selectedDate, setSelectedDate] = useState<string>("");

  if (!sessions || sessions.length === 0) return null;

  return (
    <>
      <div className="rounded-md border bg-card">
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Medical Specialist</TableHead>
              <TableHead>Chief Complaint</TableHead>
              <TableHead>Date</TableHead>
              <TableHead className="text-right">Action</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {sessions.map((session) => (
              <TableRow key={session.id}>
                <TableCell className="font-medium">
                  {session.selectedDoctor?.specialist || "Unknown"}
                </TableCell>
                <TableCell className="text-muted-foreground line-clamp-1 max-w-xs">
                  {session.notes}
                </TableCell>
                <TableCell>{moment(session.createdOn).fromNow()}</TableCell>
                <TableCell className="text-right">
                  {session.report ? (
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => {
                        setSelectedReport(session.report);
                        setSelectedDate(session.createdOn);
                      }}
                    >
                      View Report
                    </Button>
                  ) : (
                    <Badge variant="secondary">Incomplete</Badge>
                  )}
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </div>

      <Dialog
        open={!!selectedReport}
        onOpenChange={(open) => !open && setSelectedReport(null)}
      >
        <DialogContent className="sm:max-w-2xl max-h-[90vh] overflow-y-auto">
          {selectedReport && (
            <>
              <DialogHeader>
                <DialogTitle className="text-2xl font-bold flex items-center justify-between">
                  Medical Consultation Report
                  <Badge variant="outline">
                    {moment(selectedDate).format("MMMM Do YYYY")}
                  </Badge>
                </DialogTitle>
                <DialogDescription>
                  Consultation with {selectedReport.agentName}
                </DialogDescription>
              </DialogHeader>

              <div className="space-y-6 py-4">
                <div>
                  <h4 className="font-semibold text-lg border-b pb-2 mb-2">Chief Complaint</h4>
                  <p className="text-muted-foreground">{selectedReport.chiefComplaint}</p>
                </div>

                <div>
                  <h4 className="font-semibold text-lg border-b pb-2 mb-2">Summary</h4>
                  <p className="text-muted-foreground">{selectedReport.summary}</p>
                </div>

                {selectedReport.symptoms && selectedReport.symptoms.length > 0 && (
                  <div>
                    <h4 className="font-semibold text-lg border-b pb-2 mb-2">Symptoms</h4>
                    <ul className="list-disc pl-5 space-y-1">
                      {selectedReport.symptoms.map((s, i) => (
                        <li key={i} className="text-muted-foreground">
                          <span className="font-medium text-foreground">{s.symptom}</span> - {s.severity} (Duration: {s.duration})
                        </li>
                      ))}
                    </ul>
                  </div>
                )}

                {selectedReport.medicationMentioned && selectedReport.medicationMentioned.length > 0 && (
                  <div>
                    <h4 className="font-semibold text-lg border-b pb-2 mb-2">Medications Mentioned</h4>
                    <ul className="list-disc pl-5 space-y-1">
                      {selectedReport.medicationMentioned.map((m, i) => (
                        <li key={i} className="text-muted-foreground">
                          <span className="font-medium text-foreground">{m.name}</span> - {m.dosage} ({m.frequency})
                        </li>
                      ))}
                    </ul>
                  </div>
                )}

                {selectedReport.recommendations && selectedReport.recommendations.length > 0 && (
                  <div>
                    <h4 className="font-semibold text-lg border-b pb-2 mb-2">Recommendations</h4>
                    <ul className="list-disc pl-5 space-y-1">
                      {selectedReport.recommendations.map((rec, i) => (
                        <li key={i} className="text-muted-foreground">{rec}</li>
                      ))}
                    </ul>
                  </div>
                )}

                <div className="bg-destructive/10 text-destructive p-4 rounded-lg mt-8 text-sm flex items-start gap-2">
                  <span className="font-bold">Disclaimer:</span>
                  <span>{selectedReport.disclaimer || "This report was generated by AI. Please consult a real doctor for medical advice."}</span>
                </div>
              </div>
            </>
          )}
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import axios from "axios";
import { useEffect, useState } from "react";
import { HistoryTable } from "../_components/HistoryTable";

export default function HistoryPage() {
  const [sessions, setSessions] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchHistory = async () => {
      try {
        const res = await axios.get("/api/session-chart?sessionId=all");
        setSessions(res.data);
      } catch (error) {
        console.error("Failed to fetch sessions");
      } finally {
        setIsLoading(false);
      }
    };
    fetchHistory();
  }, []);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Consultation History</h1>
        <p className="text-muted-foreground">View all your past AI medical consultations and reports</p>
      </div>

      {isLoading ? (
        <div className="flex justify-center py-12">
          <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
        </div>
      ) : sessions.length === 0 ? (
        <div className="rounded-xl border p-8 text-center bg-muted/20">
          <p className="text-muted-foreground">No consultation history found.</p>
        </div>
      ) : (
        <HistoryTable sessions={sessions} />
      )}
    </div>
  );
}

"use client";

import { Button } from "@/components/ui/button";
import { DoctorAgent } from "@/data/doctorAgents";
import Vapi from "@vapi-ai/web";
import axios from "axios";
import { Loader2, Mic, Phone, PhoneOff, Square } from "lucide-react";
import Image from "next/image";
import { useParams, useRouter } from "next/navigation";
import { useEffect, useRef, useState } from "react";
import { toast } from "sonner";

// Initialize Vapi outside component
const vapi = new Vapi(process.env.NEXT_PUBLIC_VAPI_API_KEY!);

export default function VoiceAgentPage() {
  const params = useParams();
  const router = useRouter();
  const sessionId = params.sessionId as string;

  const [sessionData, setSessionData] = useState<any>(null);
  const [doctor, setDoctor] = useState<DoctorAgent | null>(null);
  const [callStatus, setCallStatus] = useState<"inactive" | "connecting" | "active">("inactive");
  const [messages, setMessages] = useState<{ role: string; text: string }[]>([]);
  const [liveTranscript, setLiveTranscript] = useState("");
  const [isGeneratingReport, setIsGeneratingReport] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const fetchSession = async () => {
      try {
        const res = await axios.get(`/api/session-chart?sessionId=${sessionId}`);
        if (res.data && !res.data.error) {
          setSessionData(res.data);
          setDoctor(res.data.selectedDoctor);
        } else {
          toast.error("Session not found");
          router.push("/dashboard");
        }
      } catch (error) {
        toast.error("Error loading session");
        router.push("/dashboard");
      }
    };
    if (sessionId) fetchSession();
  }, [sessionId, router]);

  // Vapi Event Listeners
  useEffect(() => {
    const onCallStart = () => {
      setCallStatus("active");
    };

    const onCallEnd = () => {
      setCallStatus("inactive");
      vapi.removeAllListeners();
      generateReport();
    };

    const onError = (e: any) => {
      console.error("Vapi Error:", e);
      setCallStatus("inactive");
      toast.error("Call error occurred");
    };

    const onMessage = (message: any) => {
      if (message.type === "transcript" && message.transcriptType === "partial") {
        setLiveTranscript(message.transcript);
      } else if (message.type === "transcript" && message.transcriptType === "final") {
        setLiveTranscript("");
        setMessages((prev) => [
          ...prev,
          { role: message.role, text: message.transcript },
        ]);
      }
    };

    vapi.on("call-start", onCallStart);
    vapi.on("call-end", onCallEnd);
    vapi.on("error", onError);
    vapi.on("message", onMessage);

    return () => {
      vapi.removeAllListeners();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [messages.length]); // Adding messages.length so it re-binds but we use functional state updates

  // Auto-scroll messages
  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, liveTranscript]);

  const startCall = async () => {
    if (!doctor) return;
    setCallStatus("connecting");

    try {
      const config = {
        name: `AI ${doctor.specialist} Voice Agent`,
        firstMessage: `Hello, I'm your AI ${doctor.specialist}. I've reviewed your notes about your symptoms. Can you tell me more about how you're feeling right now?`,
        transcriber: {
          provider: "assembly-ai",
        },
        voice: {
          provider: "playht",
          voiceId: doctor.voiceId,
        },
        model: {
          provider: "openai",
          model: "gpt-4o", // Or gpt-4
          messages: [{ role: "system", content: doctor.agentPrompt }],
        },
      };

      await vapi.start(config);
    } catch (error) {
      console.error("Failed to start call", error);
      setCallStatus("inactive");
      toast.error("Microphone access denied or connection failed");
    }
  };

  const endCall = () => {
    vapi.stop();
    setCallStatus("inactive");
  };

  const generateReport = async () => {
    if (messages.length === 0) {
      toast.info("No conversation to analyze.");
      router.push("/dashboard");
      return;
    }

    setIsGeneratingReport(true);
    toast.info("Generating medical report...", { duration: 5000 });

    try {
      await axios.post("/api/medical-report", {
        sessionId,
        sessionDetail: sessionData,
        messages,
      });
      toast.success("Report generated successfully!");
      router.push("/dashboard/history");
    } catch (error) {
      console.error("Report gen error", error);
      toast.error("Failed to generate report");
      setIsGeneratingReport(false);
      router.push("/dashboard");
    }
  };

  if (!doctor) {
    return (
      <div className="flex justify-center py-20">
        <Loader2 className="h-10 w-10 animate-spin text-primary" />
      </div>
    );
  }

  // Show only last 4 actual messages to keep UI clean, plus the live transcript below
  const displayMessages = messages.slice(-4);

  return (
    <div className="max-w-4xl mx-auto animate-in fade-in duration-500">
      <div className="rounded-2xl border bg-card shadow-lg p-6 md:p-10 flex flex-col md:flex-row gap-8 items-center md:items-start">

        {/* Doctor Info Sidebar */}
        <div className="flex flex-col items-center flex-shrink-0 w-full md:w-64 text-center">
          <div className={`relative h-32 w-32 rounded-full mb-4 overflow-hidden border-4 shadow-sm transition-colors duration-500 ${callStatus === 'active' ? 'border-green-500 ring-4 ring-green-500/20' : callStatus === 'connecting' ? 'border-yellow-500 shadow-yellow-500/50' : 'border-muted'}`}>
             <div className="absolute inset-0 flex items-center justify-center text-5xl bg-primary/10 text-primary uppercase font-bold">
               {doctor.specialist.charAt(0)}
             </div>
          </div>

          <h2 className="text-xl font-bold">{doctor.specialist}</h2>
          <p className="text-sm border rounded-full px-3 py-1 bg-secondary text-secondary-foreground mt-2 inline-flex items-center gap-2 font-medium">
            <span className={`h-2 w-2 rounded-full ${callStatus === 'active' ? 'bg-green-500 animate-pulse' : callStatus === 'connecting' ? 'bg-yellow-500 animate-pulse' : 'bg-red-500'}`} />
            {callStatus === 'active' ? 'Connected' : callStatus === 'connecting' ? 'Connecting...' : 'Not Connected'}
          </p>

          <p className="text-xs text-muted-foreground mt-4 line-clamp-3">
            AI Medical Assistant powered by Vapi & GPT-4
          </p>
        </div>

        {/* Conversation Area */}
        <div className="flex-1 w-full flex flex-col bg-muted/30 rounded-xl p-4 md:p-6 min-h-[400px]">
          <div className="flex-1 space-y-4 overflow-y-auto pr-2 pb-4 flex flex-col justify-end">

            {displayMessages.length === 0 && !liveTranscript && (
              <div className="text-center text-muted-foreground py-10 flex flex-col items-center">
                <Mic className="h-12 w-12 text-muted-foreground/30 mb-4" />
                <p>Start the call to begin conversation.</p>
                <p className="text-xs mt-2 max-w-xs mx-auto">Make sure your microphone is connected and you grant browser permissions.</p>
              </div>
            )}

            {displayMessages.map((msg, i) => (
              <div
                key={i}
                className={`flex flex-col max-w-[85%] animate-in slide-in-from-bottom-2 ${
                  msg.role === "assistant" ? "self-start items-start" : "self-end items-end"
                }`}
              >
                <span className="text-xs text-muted-foreground mb-1 ml-1">
                  {msg.role === "assistant" ? doctor.specialist : "You"}
                </span>
                <div
                  className={`rounded-2xl px-4 py-3 ${
                    msg.role === "assistant"
                      ? "bg-card border shadow-sm rounded-tl-sm text-foreground"
                      : "bg-primary text-primary-foreground rounded-tr-sm"
                  }`}
                >
                  {msg.text}
                </div>
              </div>
            ))}

            {/* Live partial transcript */}
            {liveTranscript && (
              <div className="flex flex-col max-w-[85%] self-end items-end animate-in fade-in">
                <span className="text-xs text-muted-foreground mb-1 ml-1 flex items-center gap-1">
                  <div className="h-1.5 w-1.5 rounded-full bg-primary animate-pulse" />
                  You
                </span>
                <div className="rounded-2xl px-4 py-3 bg-primary/80 text-primary-foreground rounded-tr-sm select-none opacity-80 backdrop-blur-sm">
                  {liveTranscript}
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Controls */}
          <div className="mt-4 pt-4 border-t flex justify-center border-border/50">
            {isGeneratingReport ? (
              <Button disabled className="w-full sm:w-auto h-12 px-8 text-md font-semibold">
                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                Generating Medical Report...
              </Button>
            ) : callStatus === "inactive" ? (
              <Button 
                onClick={startCall} 
                className="w-full sm:w-auto h-12 px-8 text-md font-semibold bg-primary hover:bg-primary/90 transition-all rounded-full shadow-lg hover:shadow-primary/25"
              >
                <Phone className="mr-2 h-5 w-5" />
                Start Consultation Call
              </Button>
            ) : callStatus === "connecting" ? (
              <Button disabled variant="outline" className="w-full sm:w-auto h-12 px-8 text-md font-semibold rounded-full border-2">
                <Loader2 className="mr-2 h-5 w-5 animate-spin" />
                Connecting...
              </Button>
            ) : (
              <Button 
                onClick={endCall} 
                variant="destructive" 
                className="w-full sm:w-auto h-12 px-8 text-md font-semibold animate-pulse hover:animate-none rounded-full shadow-lg"
              >
                <PhoneOff className="mr-2 h-5 w-5" />
                End Call & Generate Report
              </Button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

"use client";

import { useUserDetail } from "@/app/provider";
import { Button } from "@/components/ui/button";
import { DoctorAgent, doctorAgents } from "@/data/doctorAgents";
import axios from "axios";
import { FileHeart, Plus } from "lucide-react";
import Image from "next/image";
import { useEffect, useState } from "react";
import { AddNewSessionDialog } from "./_components/AddNewSessionDialog";
import { DoctorAgentCard } from "./_components/DoctorAgentCard";
import { HistoryTable } from "./_components/HistoryTable";

export default function DashboardPage() {
  const { userDetail } = useUserDetail();
  const [sessions, setSessions] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);

  // Free users only get access if they have No history
  const isPaidUser = userDetail?.credits === 9999; // Simple check for this demo or check publicMetadata

  useEffect(() => {
    const fetchHistory = async () => {
      try {
        const res = await axios.get("/api/session-chart?sessionId=all");
        setSessions(res.data);
      } catch (error) {
        console.error("Failed to fetch sessions");
      } finally {
        setIsLoading(false);
      }
    };
    fetchHistory();
  }, []);

  const handleDoctorSelect = async (doctor: DoctorAgent) => {
    if (doctor.subscriptionRequired && !isPaidUser) return;
    setIsDialogOpen(true);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">My Dashboard</h1>
          <p className="text-muted-foreground">Manage your AI medical consultations</p>
        </div>
        <Button onClick={() => setIsDialogOpen(true)} className="gap-2 shrink-0">
          <Plus className="h-4 w-4" /> Consult with Doctor
        </Button>
      </div>

      <div className="pt-4">
        <h2 className="text-xl font-semibold mb-4">Recent Consultations</h2>

        {isLoading ? (
          <div className="flex justify-center py-12">
            <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
          </div>
        ) : sessions.length === 0 ? (
          <div className="flex flex-col items-center justify-center rounded-xl border border-dashed p-12 text-center bg-muted/20">
            <div className="rounded-full bg-primary/10 p-4 mb-4">
              <FileHeart className="h-8 w-8 text-primary" />
            </div>
            <h3 className="text-lg font-semibold">No recent consultations</h3>
            <p className="text-sm text-muted-foreground mt-1 mb-4 max-w-sm">
              You haven't had any AI medical consultations yet. Choose a specialist below to get started.
            </p>
            <Button onClick={() => setIsDialogOpen(true)}>Start a Consultation</Button>
          </div>
        ) : (
          <HistoryTable sessions={sessions.slice(0, 3)} />
        )}
      </div>

      <div className="pt-8 space-y-4">
        <div>
          <h2 className="text-xl font-semibold">AI Specialist Doctor Agents</h2>
          <p className="text-sm text-muted-foreground">Select a specialist for your consultation</p>
        </div>

        <div className="grid gap-6 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
          {doctorAgents.map((doctor) => (
            <DoctorAgentCard
              key={doctor.id}
              doctor={doctor}
              onSelect={handleDoctorSelect}
              isPaidUser={isPaidUser}
            />
          ))}
        </div>
      </div>

      <AddNewSessionDialog
        isOpen={isDialogOpen}
        onOpenChange={setIsDialogOpen}
        isPaidUser={isPaidUser}
        hasHistory={sessions.length > 0}
      />
    </div>
  );
}

import { clerkClient } from "@clerk/nextjs/server";

export async function checkProStatus(userId: string | null): Promise<boolean> {
  if (!userId) return false;

  try {
    const client = await clerkClient();
    const user = await client.users.getUser(userId);
    // In Clerk, you might store subscription data in publicMetadata
    // Or check active subscriptions via Stripe API if integrated
    // For this boilerplate, we'll assume it's true if `plan === 'pro'` is in metadata
    return user.publicMetadata?.plan === "pro";
  } catch (error) {
    return false;
  }
}
